import pytest
import requests

def test_get_api_v2_enroll_multiple_bad_fields(base_url):
    data = {
        "user_id": -1,
        "name": 123,
        "base64_image": "invalid_base64_string"
    }
    resp = requests.post(f"{base_url}/api/v2/enroll", json=data, timeout=10)
    body = resp.json()
    assert body.get("success") == False or body.get("error_code", 0) < 0, (
        f"Expected error but got: {resp.text[:300]}"
    )

